#include <stdio.h>
#include <string.h>

int isPalindrome(char *s, int *seq, int len) {
    int i, j;
    for (i = 0, j = len - 1; i < j; i++, j--) {
        if (s[seq[i]] != s[seq[j]]) return 0;
    }
    return 1;
}

int countExponentialSequences(char *s, int n) {
    int count = 0;
    for (int len = 1; len <= n; len++) {
        for (int i = 0; i < n; i++) {
            int seq[len];
            seq[0] = i;
            int j = 1;
            int p = 2;
            while (j < len && seq[j - 1] * p < n) {
                seq[j] = seq[j - 1] * p;
                j++;
                p++;
            }
            if (j == len && isPalindrome(s, seq, len)) count++;
        }
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[500001];
        scanf("%s", s);
        int n = strlen(s);
        printf("%d\n", countExponentialSequences(s, n));
    }
    return 0;
}

