import java.util.Scanner;
public class Main {
    public static int isPalindrome(String s, int[] seq, int len) {
        int i, j;
        for (i = 0, j = len - 1; i < j; i++, j--) {
            if (s.charAt(seq[i]) != s.charAt(seq[j])) return 0;
        }
        return 1;
    }

