        int count = 0;
        for (int len = 1; len <= n; len++) {
            for (int i = 0; i < n; i++) {
                int[] seq = new int[len];
                seq[0] = i;
                int j = 1;
                int p = 2;
                while (j < len && seq[j - 1] * p < n) {
                    seq[j] = seq[j - 1] * p;
                    j++;
                    p++;
                }
                if (j == len && isPalindrome(s, seq, len) == 1) count++;
            }
