def is_palindrome(s, seq, len):
    i, j = 0, len - 1
    while i < j:
        if s[seq[i]] != s[seq[j]]:
            return 0
        i += 1
        j -= 1
    return 1

def count_exponential_sequences(s, n):
    count = 0
    for length in range(1, n + 1):
        for i in range(n):
            seq = [i]
            j = 1
            p = 2
            while j < length and seq[j - 1] * p < n:
                seq.append(seq[j - 1] * p)
                j += 1
                p += 1
            if j == length and is_palindrome(s, seq, length):
                count += 1
    return count

